import{_ as t,o as a,c as e,ag as r}from"./chunks/framework.Bgwu_dgr.js";const g=JSON.parse('{"title":"코드, 세계와의 인터페이스","description":"","frontmatter":{},"headers":[],"relativePath":"topics/code-as-interface.md","filePath":"topics/code-as-interface.md","lastUpdated":null}'),l={name:"topics/code-as-interface.md"};function n(i,o,s,u,d,c){return a(),e("div",null,[...o[0]||(o[0]=[r('<h1 id="코드-세계와의-인터페이스" tabindex="-1">코드, 세계와의 인터페이스 <a class="header-anchor" href="#코드-세계와의-인터페이스" aria-label="Permalink to &quot;코드, 세계와의 인터페이스&quot;">​</a></h1><p>Anthropic이 Claude Code를 만들면서 얻은 가장 중요한 통찰은, 역설적으로 &quot;코딩&quot;에 대한 것이 아니었다. Zhang과 Murag은 그 통찰을 이렇게 요약한다.</p><blockquote><p>코드는 단순한 사용 사례가 아니다. 코드는 **디지털 세계와 대화하는 보편 인터페이스(universal interface)**다.</p></blockquote><p>이 관찰이 이 발표 전체의 기술적 토대를 이룬다. 스킬이 &quot;도구(tool)&quot;가 아닌 &quot;스크립트&quot;로 설계된 이유도, MCP가 스킬과 공존할 수 있는 이유도, 모두 이 명제에서 출발한다.</p><h2 id="claude-code는-사실-범용-에이전트다" tabindex="-1">Claude Code는 사실 범용 에이전트다 <a class="header-anchor" href="#claude-code는-사실-범용-에이전트다" aria-label="Permalink to &quot;Claude Code는 사실 범용 에이전트다&quot;">​</a></h2><p>Claude Code는 &quot;코딩 에이전트&quot;라는 이름으로 출시되었지만, 실제 사용 패턴을 보면 그 이름이 좁은 것이었음이 드러난다.</p><ul><li>재무팀이 Claude Code에게 엑셀 데이터를 받아 피벗 리포트를 생성하게 한다.</li><li>연구자가 CSV와 Python을 써서 데이터 분석을 돌린다.</li><li>운영팀이 수백 개의 파일을 규칙에 따라 재배치하게 시킨다.</li></ul><p>이 모든 것은 겉보기에는 서로 다른 도메인의 업무다. 그런데 공통점은 명확하다. <strong>결국 코드가 매개한다.</strong> 파이썬 스크립트, 셸 명령, SQL, JSON 변환 -- 모두가 디지털 산출물을 만들거나 조작하는 보편 언어다.</p><p>이 관찰에서 Anthropic은 큰 의사결정을 한다. &quot;도메인별 에이전트를 따로 만들지 말고, <strong>코드를 다룰 줄 아는 범용 에이전트</strong>를 만들자.&quot; Claude Code는 코더만을 위한 도구가 아니라, 디지털 세계의 모든 작업을 코드라는 공통 언어로 해결하는 인터페이스다.</p><h2 id="왜-코드가-보편적인가" tabindex="-1">왜 코드가 보편적인가 <a class="header-anchor" href="#왜-코드가-보편적인가" aria-label="Permalink to &quot;왜 코드가 보편적인가&quot;">​</a></h2><p>Zhang과 Murag은 코드가 갖는 몇 가지 속성을 짚는다. 이 속성들은 에이전트 설계에 결정적이다.</p><p><strong>1. 결정적 실행(Deterministic Execution)</strong><br> 자연어는 해석의 여지가 있지만, 코드는 한 번 실행되면 같은 입력에 같은 출력을 낸다. 에이전트가 &quot;다섯 건의 송장을 검증하라&quot;는 지시를 매번 다르게 해석한다면 실무에 투입할 수 없다. 스크립트를 통해서만 <strong>일관성의 보장</strong>이 가능하다.</p><p><strong>2. 구성 가능성(Composability)</strong><br> 스크립트는 다른 스크립트를 호출할 수 있고, 파이프라인을 이룰 수 있다. 에이전트가 수행하는 복잡한 작업은 사실 작은 스크립트들의 조합이다.</p><p><strong>3. 관찰 가능성(Observability)</strong><br> 스크립트가 실행되면 로그와 출력이 남는다. 에이전트는 이 결과를 읽고 다음 행동을 결정할 수 있다. 자연어 응답과는 다른, 명확하고 기계 가독적인 피드백 루프가 생긴다.</p><p><strong>4. 수정 가능성(Modifiability)</strong><br> 스크립트가 기대와 다르게 동작하면 에이전트는 파일을 열어 직접 고칠 수 있다. 이것이 &quot;도구&quot;와 &quot;스크립트&quot;를 가르는 결정적 차이다.</p><h2 id="도구-tool-가-아닌-스크립트-script" tabindex="-1">도구(Tool)가 아닌 스크립트(Script) <a class="header-anchor" href="#도구-tool-가-아닌-스크립트-script" aria-label="Permalink to &quot;도구(Tool)가 아닌 스크립트(Script)&quot;">​</a></h2><p>전통적인 에이전트 설계에서 &quot;도구&quot;는 에이전트가 호출하는 사전 정의된 함수였다. <code>send_email(to, subject, body)</code>, <code>calculate_vat(amount)</code> 같은 것들. 이 방식에는 두 가지 구조적 한계가 있다.</p><ul><li><strong>모호성</strong> -- 도구의 설명문이 아무리 정교해도, 엣지 케이스에서 에이전트는 오판한다. &quot;<code>amount</code>가 음수면 어떻게 하지? 통화가 JPY면?&quot; -- 문서에 없으면 추측한다.</li><li><strong>블랙박스성</strong> -- 도구의 내부를 에이전트가 보거나 고칠 수 없다. 한 번 잘못 정의된 도구는 다음 사용자가 또 같은 문제를 겪는다.</li></ul><p>스킬 안의 스크립트는 이 두 문제를 동시에 해결한다. <strong>코드가 자신의 정확한 동작을 설명한다.</strong> 그리고 <strong>잘못된 동작은 수정될 수 있다.</strong></p><p>Zhang과 Murag은 이 점에서 흥미로운 주장을 한다. 에이전트의 능력을 늘리는 &quot;올바른 방법&quot;은 도구의 개수를 늘리는 것이 아니라, <strong>스크립트가 놓일 파일 시스템과 실행 환경을 제공하는 것</strong>이다.</p><h2 id="런타임이-이미-코드를-실행할-수-있다면" tabindex="-1">런타임이 이미 코드를 실행할 수 있다면 <a class="header-anchor" href="#런타임이-이미-코드를-실행할-수-있다면" aria-label="Permalink to &quot;런타임이 이미 코드를 실행할 수 있다면&quot;">​</a></h2><p>이 통찰이 스킬 설계로 자연스럽게 이어진다. 만약 에이전트가 이미 코드를 실행하는 환경을 가졌다면(Claude Code가 그렇다), 스킬은 그저 <strong>그 환경에 던져둘 파일들</strong>이면 충분하다. 별도의 &quot;도구 등록&quot;도, &quot;플러그인 인터페이스&quot;도 필요 없다.</p><ul><li>스킬은 폴더다.</li><li>에이전트는 폴더 안의 <code>SKILL.md</code>를 읽는다.</li><li>필요한 스크립트를 실행한다.</li><li>결과를 받아 다음 단계로 간다.</li></ul><p>이 흐름에는 새로운 추상화가 없다. 운영체제의 파일 시스템과 프로세스 실행이라는, 이미 50년 넘게 검증된 메커니즘 위에 올라탄다. 이것이 스킬의 확장성과 단순성을 동시에 가능하게 한다.</p><h2 id="mcp와의-관계-대체가-아닌-보완" tabindex="-1">MCP와의 관계 -- 대체가 아닌 보완 <a class="header-anchor" href="#mcp와의-관계-대체가-아닌-보완" aria-label="Permalink to &quot;MCP와의 관계 -- 대체가 아닌 보완&quot;">​</a></h2><p>발표의 후반부에서 이 명제는 Model Context Protocol(MCP)과의 관계로 확장된다.</p><ul><li><strong>MCP</strong> -- 외부 세계와의 <strong>연결</strong>. API, 데이터베이스, SaaS 도구.</li><li><strong>스킬</strong> -- 그 연결 위에서 수행되는 <strong>절차적 전문성</strong>.</li></ul><p>세무 처리를 예로 들면, MCP가 회계 시스템과 세무 당국 API에 연결하는 배관이라면, 스킬은 &quot;이 회사의 분기 세무 처리는 이런 순서로 한다&quot;는 플레이북이다. 둘은 대체재가 아니라 보완재다.</p><p>그리고 이 둘을 하나로 묶는 매개가 바로 <strong>코드</strong>다. MCP의 연결을 호출하는 것도, 스킬의 절차를 수행하는 것도, 결국 런타임 위에서 실행되는 코드 조각이다. 이것이 &quot;코드는 디지털 세계의 보편 인터페이스&quot;라는 명제의 완전한 형태다.</p>',29)])])}const q=t(l,[["render",n]]);export{g as __pageData,q as default};
